  ('optician-moex-01313', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有一軟式水膠鏡片未水化前重量1.5公克，水化後重2.5公克，含水量多少？', '["10%", "40%", "50%", "66%"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "c416a992b3fa", "answer_pdf_sha1": "508637df230d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 1, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01314', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關軟式隱形眼鏡與硬式透氧隱形眼鏡（RGP）的比較，下列敘述何者錯誤？', '["軟式隱形眼鏡的光學視覺相對表現較佳", "硬式透氧隱形眼鏡相對於軟式水膠隱形眼鏡有較佳的保持表面濕潤度（surfacewettability）", "軟式隱形眼鏡相對較不耐用", "硬式透氧隱形眼鏡產生感染性角膜炎的比例相對較低"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "c416a992b3fa", "answer_pdf_sha1": "508637df230d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 2, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01315', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '依據美國食品和藥物管理局（FDA）對軟式隱形眼鏡分類中，有關非離子性水膠隱形眼鏡，下列敘述何者 正確？', '["低含水量水膠隱形眼鏡，材質中有加入甲基丙烯酸（methacrylicacid,MAA）來增加硬度", "高含水量水膠隱形眼鏡，不適合使用加熱式的消毒方式", "低含水量水膠隱形眼鏡，蛋白質較容易沉積在鏡片上，但因為非離子性的特質，故不易與其它沉積物相 互作用", "高含水量水膠隱形眼鏡，蛋白質較不易沉積在鏡片上"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "c416a992b3fa", "answer_pdf_sha1": "508637df230d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 3, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01316', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關軟式隱形眼鏡材質甲基丙烯酸羥乙酯（2-hydroxyethylmethacrylate,HEMA）的優點，下列敘述何者錯誤？', '["具備親水性（hydrophilic）", "具備柔軟性（softness）", "具備濕潤度（wettability）", "具備好的透氧率（oxygenpermeability,Dk）"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "c416a992b3fa", "answer_pdf_sha1": "508637df230d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 4, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01317', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關軟式水膠隱形眼鏡之含水量敘述，下列何者正確？', '["鏡片含水量80%之折射率（refractiveindex）比鏡片含水量42%之折射率低", "含水量越高，其鏡片越不透氧", "含水量越高，其鏡片越不柔軟", "當鏡片存放在高滲透壓溶液中，鏡片容易吸水造成含水量升高"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "c416a992b3fa", "answer_pdf_sha1": "508637df230d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 5, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL),
  ('optician-moex-01318', 'optician', 'optician-moex-109-72ff33b8', 'sub-optician-03', NULL, 'single_choice', '有關硬式透氧隱形眼鏡的敘述，下列敘述何者正確？', '["光學直徑較大或中央厚度較厚的鏡片，會產生較大的抗彎性", "材質濕潤角（θ）的角度越小，表示濕潤性程度越差", "配戴久了可能會有眼皮下垂的問題", "RGP發生角膜水腫和巨乳突狀結膜炎（giantpapillaryconjunctivitis,GPC）的機率與軟式隱形眼鏡差不多"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T07:17:33+00:00", "source_pdf_sha1": "c416a992b3fa", "answer_pdf_sha1": "508637df230d", "source_family": "moex-gov-tw", "moex": {"exam_code": "109060", "c": "402", "s": "0808", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "隱形眼鏡學概要", "year": "109", "exam_name": "109年專技人員高等考試大地工程技師考試分階段考試（第一階段考試）、驗船師、第一次食品技師考試、高等暨普通考試消防設備人員考試、普通考試地政...", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "optician", "db_exam_id": "optician"}'::jsonb, NULL)
